using System.Collections.Generic;\nusing System.Threading.Tasks;\nusing kaniamine.rh_management_system.Models;\n\nnamespace kaniamine.rh_management_system.Repositories\n{\n    public interface IDemandeCongeRepository\n    {\n        Task<IEnumerable<DemandeConge>> GetAllDemandeCongesAsync();\n        Task<DemandeConge> GetDemandeCongeByIdAsync(int id);\n        Task AddDemandeCongeAsync(DemandeConge demandeConge);\n        Task UpdateDemandeCongeAsync(DemandeConge demandeConge);\n        Task DeleteDemandeCongeAsync(int id);\n    }\n\n    public class DemandeCongeRepository : IDemandeCongeRepository\n    {\n        private readonly ApplicationDbContext _context;\n\n        public DemandeCongeRepository(ApplicationDbContext context)\n        {\n            _context = context;\n        }\n\n        public async Task<IEnumerable<DemandeConge>> GetAllDemandeCongesAsync()\n        {\n            return await _context.DemandeConges.ToListAsync();\n        }\n\n        public async Task<DemandeConge> GetDemandeCongeByIdAsync(int id)\n        {\n            return await _context.DemandeConges.FindAsync(id);\n        }\n\n        public async Task AddDemandeCongeAsync(DemandeConge demandeConge)\n        {\n            await _context.DemandeConges.AddAsync(demandeConge);\n            await _context.SaveChangesAsync();\n        }\n\n        public async Task UpdateDemandeCongeAsync(DemandeConge demandeConge)\n        {\n            _context.DemandeConges.Update(demandeConge);\n            await _context.SaveChangesAsync();\n        }\n\n        public async Task DeleteDemandeCongeAsync(int id)\n        {\n            var demandeConge = await _context.DemandeConges.FindAsync(id);\n            if (demandeConge != null)\n            {\n                _context.DemandeConges.Remove(demandeConge);\n                await _context.SaveChangesAsync();\n            }\n        }\n    }\n}